const fs = require('fs');

const sourcePath = '/home/node/analysis/top50.csv';
const outputPath = '/files/workflows/demo/staging_output.csv';

function splitCsvLine(line) {
  const cells = [];
  let current = '';
  let inQuotes = false;

  for (let i = 0; i < line.length; i += 1) {
    const char = line[i];

    if (char === '"') {
      if (inQuotes && line[i + 1] === '"') {
        current += '"';
        i += 1;
      } else {
        inQuotes = !inQuotes;
      }
      continue;
    }

    if (char === ',' && !inQuotes) {
      cells.push(current);
      current = '';
      continue;
    }

    current += char;
  }

  cells.push(current);
  return cells;
}

function parseCsv(text) {
  const normalized = text.replace(/^\uFEFF/, '').trim();
  const lines = normalized.split(/\r?\n/).filter((line) => line.trim().length > 0);
  if (lines.length < 2) {
    throw new Error('WF-2 expected CSV headers and data rows');
  }

  const headers = splitCsvLine(lines[0]).map((header) => header.trim());
  return lines.slice(1).map((line) => {
    const values = splitCsvLine(line);
    const row = {};
    headers.forEach((header, index) => {
      row[header] = values[index] ?? '';
    });
    return row;
  });
}

function escapeCsv(value) {
  const text = value === null || value === undefined ? '' : String(value);
  return /[",\n\r]/.test(text) ? `"${text.replace(/"/g, '""')}"` : text;
}

const rows = parseCsv(fs.readFileSync(sourcePath, 'utf8'));
const tierB = rows.filter((row) => String(row.tier).trim().toUpperCase() === 'B');

const enrichedRows = tierB.map((row, index) => ({
  brand_id: row.brand_id,
  tier: row.tier,
  category: row.category,
  gmv_cop_millions_12m: row.gmv_cop_millions_12m,
  n_unique_clients_12m: row.n_unique_clients_12m,
  gmv_90d_to_12m_ratio: row.gmv_90d_to_12m_ratio,
  days_since_last_orig: row.days_since_last_orig,
  recency_score: row.recency_score,
  fit_score: row.fit_score,
  momentum_score: row.momentum_score,
  category_bonus: row.category_bonus,
  final_score: row.final_score,
  why: row.why,
  routing: row.routing,
  _rowIndex: index,
  enrichment_status: 'simulado_local',
  contacto_nombre: '',
  contacto_email: '',
  contacto_cargo: '',
  linkedin_url: '',
  cms_detectado: '',
  dominio_sitio: ''
}));

const headers = [
  'brand_id',
  'tier',
  'category',
  'gmv_cop_millions_12m',
  'n_unique_clients_12m',
  'gmv_90d_to_12m_ratio',
  'days_since_last_orig',
  'recency_score',
  'fit_score',
  'momentum_score',
  'category_bonus',
  'final_score',
  'why',
  'routing',
  '_rowIndex',
  'enrichment_status',
  'contacto_nombre',
  'contacto_email',
  'contacto_cargo',
  'linkedin_url',
  'cms_detectado',
  'dominio_sitio'
];

const csv = [
  headers.join(','),
  ...enrichedRows.map((row) => headers.map((header) => escapeCsv(row[header])).join(','))
].join('\n') + '\n';

fs.mkdirSync('/files/workflows/demo', { recursive: true });
fs.writeFileSync(outputPath, csv, 'utf8');

return [
  {
    json: {
      timestamp: new Date().toISOString(),
      source_path: sourcePath,
      output_path: outputPath,
      total_rows: rows.length,
      tier_b_count: tierB.length,
      enriched_rows: enrichedRows.length
    }
  }
];
